          ..write('customerId: $customerId, ')
          ..write('type: $type, ')
          ..write('points: $points, ')
          ..write('reference: $reference, ')
          ..write('description: $description, ')
          ..write('createdAt: $createdAt, ')
          ..write('rowid: $rowid')
          ..write(')'))
        .toString();
  }
}

